package policy

import (
	"context"
	"io"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyVerdict represents the verdict of a policy evaluation.
type PolicyVerdict string

const (
	// PolicyVerdictAllow indicates traffic is allowed.
	PolicyVerdictAllow PolicyVerdict = "allow"
	// PolicyVerdictDeny indicates traffic is denied.
	PolicyVerdictDeny PolicyVerdict = "deny"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes.
type PolicyAuditLogger struct {
	mu       lock.Mutex
	logLevel logrus.Level
	output   io.Writer
	logger   *logrus.Logger
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with the given log level
// and output writer.
func NewPolicyAuditLogger(level logrus.Level, output io.Writer) *PolicyAuditLogger {
	l := logrus.New()
	l.SetLevel(level)
	l.SetFormatter(&logrus.JSONFormatter{})
	if output != nil {
		l.SetOutput(output)
	}
	return &PolicyAuditLogger{
		logLevel: level,
		output:   output,
		logger:   l,
	}
}

// LogDecision logs a policy evaluation decision with structured fields.
// Parameters:
//   - id: the numeric identity being evaluated
//   - policyName: the name or key of the policy
//   - verdict: the policy verdict (allow or deny)
//   - reason: the reason for the verdict
func (pal *PolicyAuditLogger) LogDecision(id identity.NumericIdentity, policyName string, verdict PolicyVerdict, reason string) {
	pal.mu.Lock()
	defer pal.mu.Unlock()

	scopedLog := log.WithFields(logrus.Fields{
		logfields.Identity: id,
		"policyName":       policyName,
		"verdict":          string(verdict),
		"reason":           reason,
	})

	switch verdict {
	case PolicyVerdictAllow:
		scopedLog.Debug("policy audit: allow decision")
	case PolicyVerdictDeny:
		scopedLog.Debug("policy audit: deny decision")
	default:
		scopedLog.Debug("policy audit: decision")
	}

	// Also log to the audit logger's own output if configured
	pal.logger.WithFields(logrus.Fields{
		logfields.Identity: id,
		"policyName":       policyName,
		"verdict":          string(verdict),
		"reason":           reason,
	}).Info("policy audit decision")
}

// LogEvaluation logs a full policy evaluation event including selector cache
// interaction results.
// Parameters:
//   - ctx: context for the evaluation
//   - policyKey: a string key identifying the policy being evaluated
//   - selectorCache: the SelectorCache used during evaluation
//   - result: a string describing the evaluation result
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result string) {
	pal.mu.Lock()
	defer pal.mu.Unlock()

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey,
		"result":            result,
	}
	if selectorCache != nil {
		selectorModel := selectorCache.GetModel()
		fields["selectorCount"] = len(selectorModel)
	}

	scopedLog := log.WithFields(fields)
	scopedLog.Debug("policy audit: evaluation")

	pal.logger.WithFields(fields).Info("policy audit evaluation")
}

// SetLevel sets the log level for the audit logger.
func (pal *PolicyAuditLogger) SetLevel(level logrus.Level) {
	pal.mu.Lock()
	defer pal.mu.Unlock()
	pal.logLevel = level
	pal.logger.SetLevel(level)
}

// GetLevel returns the current log level of the audit logger.
func (pal *PolicyAuditLogger) GetLevel() logrus.Level {
	pal.mu.Lock()
	defer pal.mu.Unlock()
	return pal.logLevel
}

