package policy

import (
	"bytes"
	"context"
	"encoding/json"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/labels"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)
	require.NotNil(t, pal)
	assert.Equal(t, logrus.InfoLevel, pal.GetLevel())
}

func TestPolicyAuditLoggerLogDecisionAllow(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	id := identity.NumericIdentity(1234)
	pal.LogDecision(id, "test-policy", PolicyVerdictAllow, "matched allow rule")

	// Verify output was written
	assert.NotEmpty(t, buf.Bytes())

	// Verify JSON structure
	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)
	assert.Equal(t, "policy audit decision", entry["msg"])
	assert.Equal(t, string(PolicyVerdictAllow), entry["verdict"])
	assert.Equal(t, "test-policy", entry["policyName"])
}

func TestPolicyAuditLoggerLogDecisionDeny(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	id := identity.NumericIdentity(5678)
	pal.LogDecision(id, "deny-policy", PolicyVerdictDeny, "no matching allow rule")

	assert.NotEmpty(t, buf.Bytes())

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)
	assert.Equal(t, string(PolicyVerdictDeny), entry["verdict"])
	assert.Equal(t, "matched allow rule" != entry["reason"], true)
}

func TestPolicyAuditLoggerLogEvaluation(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	sc := NewSelectorCache(nil)
	ctx := context.Background()

	pal.LogEvaluation(ctx, "test-policy-key", sc, "evaluation complete")

	assert.NotEmpty(t, buf.Bytes())

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)
	assert.Equal(t, "policy audit evaluation", entry["msg"])
	assert.Equal(t, "test-policy-key", entry["policyKey"])
}

func TestPolicyAuditLoggerLogEvaluationNilSelectorCache(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	ctx := context.Background()
	// Should not panic with nil selector cache
	pal.LogEvaluation(ctx, "test-key", nil, "result")

	assert.NotEmpty(t, buf.Bytes())
}

func TestPolicyAuditLoggerSetLevel(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	assert.Equal(t, logrus.InfoLevel, pal.GetLevel())

	pal.SetLevel(logrus.DebugLevel)
	assert.Equal(t, logrus.DebugLevel, pal.GetLevel())

	pal.SetLevel(logrus.WarnLevel)
	assert.Equal(t, logrus.WarnLevel, pal.GetLevel())
}

func TestPolicyAuditLoggerThreadSafety(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	done := make(chan struct{})
	for i := 0; i < 10; i++ {
		go func(n int) {
			id := identity.NumericIdentity(n)
			pal.LogDecision(id, "concurrent-policy", PolicyVerdictAllow, "concurrent test")
			done <- struct{}{}
		}(i)
	}
	for i := 0; i < 10; i++ {
		<-done
	}
}

func TestPolicyVerdictConstants(t *testing.T) {
	assert.Equal(t, PolicyVerdict("allow"), PolicyVerdictAllow)
	assert.Equal(t, PolicyVerdict("deny"), PolicyVerdictDeny)
}

func TestNewPolicyAuditLoggerWithNilOutput(t *testing.T) {
	// Should not panic with nil output
	pal := NewPolicyAuditLogger(logrus.InfoLevel, nil)
	require.NotNil(t, pal)

	id := identity.NumericIdentity(100)
	// Should not panic
	pal.LogDecision(id, "test", PolicyVerdictAllow, "reason")
}

func TestPolicyAuditLoggerUsesIdentityField(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	id := identity.NumericIdentity(9999)
	pal.LogDecision(id, "identity-test", PolicyVerdictAllow, "test reason")

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)

	// identity field should be present (logfields.Identity = "identity")
	assert.NotNil(t, entry["identity"])
}

func TestPolicyAuditLoggerSelectorCacheIntegration(t *testing.T) {
	buf := &bytes.Buffer{}
	pal := NewPolicyAuditLogger(logrus.InfoLevel, buf)

	// Create a real SelectorCache and add some identities
	sc := NewSelectorCache(nil)
	idCache := identity.IdentityMap{
		identity.NumericIdentity(100): labels.LabelArray{},
		identity.NumericIdentity(200): labels.LabelArray{},
	}
	sc.UpdateIdentities(idCache, nil, nil)

	ctx := context.Background()
	pal.LogEvaluation(ctx, "integration-key", sc, "with identities")

	var entry map[string]interface{}
	err := json.Unmarshal(buf.Bytes(), &entry)
	require.NoError(t, err)
	assert.Equal(t, "policy audit evaluation", entry["msg"])
}

